SELECT COUNT(*) AS sub_techniques_count 
FROM cve_cwe 
WHERE cwe_id = 'CWE-1059';

SELECT COUNT(*) AS total_cves
FROM cve AS c
WHERE c.published LIKE '2022%' AND c.cvss_v3_score > 9.0;

SELECT (COUNT(CASE WHEN cv.cvss_v3_severity IN ('HIGH', 'CRITICAL') THEN 1 END) * 100.0 / COUNT(*)) AS percentage
FROM cve AS cv
WHERE cv.published >= '2023-01-01' AND cv.published < '2024-01-01';
